+        assert_eq!(FaultIsolationManager::to_invariant_domain(FaultDomain::Recovery), InvariantDomain::Recovery);
+        assert_eq!(FaultIsolationManager::to_invariant_domain(FaultDomain::Io), InvariantDomain::Composition);
